def mk_msg(content:Union[list,str], role:str="user", *args, api:str="openai", text_only=False, **kw)-&gt;dict:
    "Create an OpenAI/Anthropic compatible message."
    m = OpenAiMsg if api == "openai" else AnthropicMsg
